// Simple synchronous SRAM with optional init file for simulation
// - Responds in 1 cycle when valid
// - Supports byte writes via wstrb
//Will swap to SRAM generated by SRAM-Forge later
//This module logically works well like an SRAM for sim, but will probably synthezise to a bunch of FF's! :(
(* blackbox *)
module simple_sram #(
    parameter integer WORDS = 1024,
    parameter INIT_HEX = ""
)(
    input  wire        clk,
    input  wire        resetn,

    input  wire        valid,
    output reg         ready,

    input  wire [3:0]  wstrb,
    input  wire [31:0] addr,   // byte address
    input  wire [31:0] wdata,
    output reg  [31:0] rdata
); 
    //8 RAM banks: for 1024 words, each word 32bits, so 4 rams for 512 32bit words, times 2 for 1024 words
    //1 is bottom, 2, 3, 4 is top
    //can CEN be pulsed with the valid signal? maybe for GWEN check for valid too, can do it with the addr[11] bit too maybe?
    
    supply1 vdd;
    supply0 vss;
    wire [7:0] gwen;
    wire cen_w = ~valid;
    wire [31:0] rdata_a;
    wire [31:0] rdata_b;

    assign gwen = {~(wstrb & {4{valid&addr[11]}}),~(wstrb & {4{valid&~addr[11]}})};
    // we want only if it's valid and were writing this bit for it to be 0
    // bc it's global write enable negated, so only pass it a 0 if we are ready to write it
    //expand to 8, if addr[11] is 0, activate write for bank A
    // otherwise, go gwen on for bank B

    gf180mcu_fd_ip_sram__sram512x8m8wm1 
    mem_A_1 (
        .CLK(clk), 
        .CEN(~valid), 
        .GWEN(gwen[0]),
        .WEN(8'b00000000), 
        .A(addr[10:2]),
        .D(wdata[7:0]),
        .Q(rdata_a[7:0]),
        .VDD(vdd), 
        .VSS(vss)
    );
    gf180mcu_fd_ip_sram__sram512x8m8wm1 
    mem_A_2 (
        .CLK(clk), 
        .CEN(~valid), 
        .GWEN(gwen[1]),
        .WEN(8'b00000000), 
        .A(addr[10:2]),
        .D(wdata[15:8]),
        .Q(rdata_a[15:8]),
        .VDD(vdd), 
        .VSS(vss)
    );
    gf180mcu_fd_ip_sram__sram512x8m8wm1 
    mem_A_3 (
        .CLK(clk), 
        .CEN(~valid), 
        .GWEN(gwen[2]),
        .WEN(8'b00000000), 
        .A(addr[10:2]),
        .D(wdata[23:16]),
        .Q(rdata_a[23:16]),
        .VDD(vdd), 
        .VSS(vss)
    );
    gf180mcu_fd_ip_sram__sram512x8m8wm1 
    mem_A_4 (
        .CLK(clk), 
        .CEN(~valid), 
        .GWEN(gwen[3]),
        .WEN(8'b00000000), 
        .A(addr[10:2]),
        .D(wdata[31:24]),
        .Q(rdata_a[31:24]),
        .VDD(vdd), 
        .VSS(vss)
    );

    gf180mcu_fd_ip_sram__sram512x8m8wm1 
    mem_B_1 (
        .CLK(clk), 
        .CEN(~valid), 
        .GWEN(gwen[4]),
        .WEN(8'b00000000), 
        .A(addr[10:2]),
        .D(wdata[7:0]),
        .Q(rdata_b[7:0]),
        .VDD(vdd), 
        .VSS(vss)
    );
    gf180mcu_fd_ip_sram__sram512x8m8wm1 
    mem_B_2 (
        .CLK(clk), 
        .CEN(~valid), 
        .GWEN(gwen[5]),
        .WEN(8'b00000000), 
        .A(addr[10:2]),
        .D(wdata[15:8]),
        .Q(rdata_b[15:8]),
        .VDD(vdd), 
        .VSS(vss)
    );
    gf180mcu_fd_ip_sram__sram512x8m8wm1 
    mem_B_3 (
        .CLK(clk), 
        .CEN(~valid), 
        .GWEN(gwen[6]),
        .WEN(8'b00000000), 
        .A(addr[10:2]),
        .D(wdata[23:16]),
        .Q(rdata_b[23:16]),
        .VDD(vdd), 
        .VSS(vss)
    );
    gf180mcu_fd_ip_sram__sram512x8m8wm1 
    mem_B_4 (
        .CLK(clk), 
        .CEN(~valid), 
        .GWEN(gwen[7]),
        .WEN(8'b00000000), 
        .A(addr[10:2]),
        .D(wdata[31:24]),
        .Q(rdata_b[31:24]),
        .VDD(vdd), 
        .VSS(vss)
    );

    //assign rdata = (addr[11]) ? rdata_b : rdata_a;

    reg valid_r; //probably should just be sending this read signal out and have a true ready valid interface, talk to rishi about it
    always @(posedge clk) begin
        if (!resetn) begin
            valid_r <= 1'b0;
            ready   <= 1'b0;
            rdata   <= 32'h0;
        end else begin
            valid_r <= valid;
            ready   <= 1'b0;
            if (valid_r) begin
                ready <= 1'b1;
                rdata <= (addr[11]) ? rdata_b : rdata_a;
            end
        end
    end
endmodule
